compliant:
public void UpdateConnectionString(string userId)
{
    // Compliant: using SqlConnectionStringBuilder with validation
    var builder = new SqlConnectionStringBuilder
    {
        DataSource = "myServer",
        InitialCatalog = "myDB",
        UserID = ValidateUserId(userId), // Validate input
        Password = "myPass"
    };
    using (SqlConnection connection = new SqlConnection(builder.ConnectionString))
    {
        // ...
    }
}
